import { Component, HostListener } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { VerificationService } from './verification.service';
import { AuthService } from './auth.service';
import { LoginComponent } from './login/login.component';
import { CatalogueComponent } from './catalogue/catalogue.component';
import { NotaryDashboardComponent } from './notary-dashboard/notary-dashboard.component';
import { TitlingTrackerComponent } from './titling-tracker/titling-tracker.component';
import { PreInvestDashboardComponent } from './pre-invest-dashboard/pre-invest-dashboard.component';
import { InvestmentMarketplaceComponent } from './investment-marketplace/investment-marketplace.component';
import { SubscriptionComponent } from './subscription/subscription.component';
import { InvestorDashboardComponent } from './investor-dashboard/investor-dashboard.component';
import { AdminDashboardComponent } from './admin-dashboard/admin-dashboard.component';

type ViewType = 'VERIFY' | 'CATALOGUE' | 'NOTARY' | 'TITRE' | 'PREINVEST' | 'COINVEST' | 'CLUB' | 'PORTFOLIO' | 'ADMIN';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [
    CommonModule, FormsModule, LoginComponent, CatalogueComponent,
    NotaryDashboardComponent, TitlingTrackerComponent, PreInvestDashboardComponent,
    InvestmentMarketplaceComponent, SubscriptionComponent, InvestorDashboardComponent,
    AdminDashboardComponent
  ],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  titleNumber = '';
  isChecking = false;
  verificationResult: any = null;
  errorMessage = '';

  deferredPrompt: any;
  showInstallButton = false;
  mobileMenuOpen = false;
  headerScrolled = false;
  viewTransition = false;

  currentView: ViewType = 'VERIFY';
  showLogin = false;
  isLoggedIn = false;
  userRole = 'BUYER';

  navItems: { view: ViewType; label: string; icon: string; authOnly?: boolean; role?: string }[] = [
    { view: 'VERIFY', label: 'Vérifier', icon: '🔍' },
    { view: 'CATALOGUE', label: 'Acheter', icon: '🏠' },
    { view: 'TITRE', label: 'Titrer', icon: '📋' },
    { view: 'PREINVEST', label: 'Pré-Investir', icon: '💡' },
    { view: 'COINVEST', label: 'Co-Investir', icon: '🤝' },
    { view: 'PORTFOLIO', label: 'Portefeuille', icon: '📊', authOnly: true },
    { view: 'NOTARY', label: 'Missions', icon: '⚖️', authOnly: true, role: 'NOTARY' },
    { view: 'ADMIN', label: 'Admin', icon: '🛡️', authOnly: true, role: 'ADMIN' },
  ];

  constructor(
    private verificationService: VerificationService,
    public authService: AuthService
  ) {
    this.isLoggedIn = this.authService.isLoggedIn();
  }

  @HostListener('window:scroll')
  onScroll() {
    this.headerScrolled = window.scrollY > 20;
  }

  @HostListener('window:beforeinstallprompt', ['$event'])
  onBeforeInstallPrompt(e: any) {
    e.preventDefault();
    this.deferredPrompt = e;
    this.showInstallButton = true;
  }

  navigate(view: ViewType) {
    if (this.currentView === view) return;
    this.viewTransition = true;
    setTimeout(() => {
      this.currentView = view;
      this.mobileMenuOpen = false;
      window.scrollTo({ top: 0, behavior: 'smooth' });
      setTimeout(() => this.viewTransition = false, 50);
    }, 150);
  }

  isNavVisible(item: any): boolean {
    if (item.authOnly && !this.isLoggedIn) return false;
    if (item.role && this.userRole !== item.role) return false;
    return true;
  }

  onLoginSuccess() {
    this.showLogin = false;
    this.isLoggedIn = true;
    this.userRole = 'NOTARY';
  }

  logout() {
    this.authService.logout();
    this.isLoggedIn = false;
    this.userRole = 'BUYER';
    this.currentView = 'VERIFY';
  }

  installPwa() {
    if (!this.deferredPrompt) return;
    this.showInstallButton = false;
    this.deferredPrompt.prompt();
    this.deferredPrompt.userChoice.then((choiceResult: any) => {
      this.deferredPrompt = null;
    });
  }

  checkTitle() {
    if (!this.titleNumber) return;
    this.isChecking = true;
    this.verificationResult = null;
    this.errorMessage = '';

    this.verificationService.submitRequest(this.titleNumber).subscribe({
      next: () => {
        this.verificationService.getPropertyStatus(this.titleNumber).subscribe({
          next: (property) => {
            this.isChecking = false;
            this.verificationResult = {
              title: property.titleNumber,
              status: property.currentStatus,
              message: this.getVerdictMessage(property.currentStatus),
              date: new Date().toLocaleDateString('fr-FR')
            };
          },
          error: () => {
            this.isChecking = false;
            this.verificationResult = {
              title: this.titleNumber,
              status: 'PENDING',
              message: 'Vérification en cours. Votre rapport sera disponible sous 48h.',
              date: new Date().toLocaleDateString('fr-FR')
            };
          }
        });
      },
      error: () => {
        this.isChecking = false;
        this.errorMessage = 'Erreur lors de la soumission. Veuillez réessayer.';
      }
    });
  }

  downloadPdf() {
    if (!this.verificationResult?.id) return;
    this.verificationService.downloadReport(this.verificationResult.id).subscribe({
      next: (blob) => {
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `Rapport_maTerre_${this.verificationResult.title}.pdf`;
        link.click();
        window.URL.revokeObjectURL(url);
      },
      error: (err) => console.error('Download error:', err)
    });
  }

  getStatusClass(status: string): string {
    switch (status) {
      case 'GREEN': return 'verdict-green';
      case 'RED': return 'verdict-red';
      case 'YELLOW': return 'verdict-yellow';
      default: return 'verdict-pending';
    }
  }

  private getVerdictMessage(status: string): string {
    switch (status) {
      case 'GREEN': return 'Titre foncier audité. Aucune charge détectée.';
      case 'RED': return 'ATTENTION : Litige foncier détecté sur ce titre.';
      case 'YELLOW': return 'PRUDENCE : Charges ou prénotations identifiées.';
      default: return 'Statut inconnu. Un arbitrage approfondi est nécessaire.';
    }
  }
}
<div class="app-shell">

  <!-- ═══ HEADER ═══ -->
  <header class="header" [class.scrolled]="headerScrolled">
    <div class="header-inner">
      <!-- Logo -->
      <a class="logo" (click)="navigate('VERIFY')">
        <img src="assets/icons/logo.png" alt="maTerre" class="logo-img">
        <div class="logo-text">
          <span class="logo-name">maTerre</span>
          <span class="logo-tagline">L'Arbitre du Foncier</span>
        </div>
      </a>

      <!-- Desktop Nav -->
      <nav class="nav-desktop">
        <ng-container *ngFor="let item of navItems">
          <button *ngIf="isNavVisible(item)"
                  class="nav-link"
                  [class.active]="currentView === item.view"
                  (click)="navigate(item.view)">
            {{ item.label }}
          </button>
        </ng-container>
        <button class="btn btn-gold btn-sm" (click)="navigate('CLUB')">
          <span>★</span> Club Elite
        </button>
      </nav>

      <!-- Auth + Mobile -->
      <div class="header-actions">
        <button *ngIf="showInstallButton" (click)="installPwa()" class="btn btn-outline btn-sm">
          Installer
        </button>
        <button *ngIf="!isLoggedIn" (click)="showLogin = true" class="btn btn-primary btn-sm">
          Se connecter
        </button>
        <div *ngIf="isLoggedIn" class="user-menu">
          <div class="user-avatar" (click)="logout()">
            <span>👤</span>
          </div>
        </div>
        <button class="hamburger" [class.open]="mobileMenuOpen" (click)="mobileMenuOpen = !mobileMenuOpen">
          <span></span><span></span><span></span>
        </button>
      </div>
    </div>
  </header>

  <!-- ═══ MOBILE MENU ═══ -->
  <div class="mobile-menu" [class.open]="mobileMenuOpen">
    <div class="mobile-menu-inner">
      <ng-container *ngFor="let item of navItems">
        <button *ngIf="isNavVisible(item)"
                class="mobile-nav-link"
                [class.active]="currentView === item.view"
                (click)="navigate(item.view)">
          <span class="mobile-nav-icon">{{ item.icon }}</span>
          {{ item.label }}
        </button>
      </ng-container>
      <button class="mobile-nav-link gold" (click)="navigate('CLUB')">
        <span class="mobile-nav-icon">★</span>
        Club Elite
      </button>
      <div class="mobile-menu-footer">
        <button *ngIf="!isLoggedIn" (click)="showLogin = true; mobileMenuOpen = false" class="btn btn-primary" style="width:100%;">
          Se connecter
        </button>
        <button *ngIf="isLoggedIn" (click)="logout(); mobileMenuOpen = false" class="btn btn-outline" style="width:100%;">
          Déconnexion
        </button>
      </div>
    </div>
  </div>

  <!-- ═══ MAIN CONTENT ═══ -->
  <main class="main-content" [class.transitioning]="viewTransition">

    <!-- ─── VERIFY (Hero) ─── -->
    <section *ngIf="currentView === 'VERIFY'" class="hero-section">
      <div class="hero-bg">
        <div class="hero-orb hero-orb-1"></div>
        <div class="hero-orb hero-orb-2"></div>
        <div class="hero-orb hero-orb-3"></div>
      </div>
      <div class="hero-content">
        <div class="hero-left animate-in">
          <div class="badge badge-gold" style="margin-bottom: 1rem;">La Clé d'un Foncier Sûr</div>
          <h1 class="hero-title">
            Vérifiez votre<br>
            <span class="text-gradient">titre foncier</span><br>
            en 48 heures
          </h1>
          <p class="hero-subtitle">
            L'arbitre digital de confiance qui sécurise votre investissement immobilier au Cameroun.
          </p>

          <!-- Search Box -->
          <div class="search-box">
            <div class="search-input-wrap">
              <span class="search-icon">🔍</span>
              <input type="text"
                     [(ngModel)]="titleNumber"
                     placeholder="Entrez le numéro de titre (ex: Vol 123 Fol 45)"
                     class="search-input"
                     (keyup.enter)="checkTitle()">
            </div>
            <button (click)="checkTitle()"
                    [disabled]="isChecking || !titleNumber"
                    class="btn btn-gold btn-lg search-btn">
              {{ isChecking ? 'Vérification...' : 'Lancer l\'Arbitrage' }}
            </button>
          </div>

          <p *ngIf="errorMessage" class="error-msg">{{ errorMessage }}</p>
        </div>

        <div class="hero-right animate-in" style="animation-delay: 200ms;">
          <div class="hero-visual">
            <img src="assets/icons/logo.png" alt="maTerre" class="hero-logo-float">
            <div class="hero-stat-cards stagger">
              <div class="stat-mini-card">
                <span class="stat-mini-value status-green">2,450+</span>
                <span class="stat-mini-label">Titres Vérifiés</span>
              </div>
              <div class="stat-mini-card">
                <span class="stat-mini-value" style="color: var(--mt-gold);">48h</span>
                <span class="stat-mini-label">Délai Moyen</span>
              </div>
              <div class="stat-mini-card">
                <span class="stat-mini-value status-green">98%</span>
                <span class="stat-mini-label">Satisfaction</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Result -->
      <div *ngIf="verificationResult" class="result-card animate-in" [ngClass]="getStatusClass(verificationResult.status)">
        <div class="result-icon">
          {{ verificationResult.status === 'GREEN' ? '✅' : verificationResult.status === 'RED' ? '🚫' : verificationResult.status === 'YELLOW' ? '⚠️' : '⏳' }}
        </div>
        <div class="result-body">
          <h3>Résultat de l'Arbitrage</h3>
          <p class="result-title-num">Titre : {{ verificationResult.title }}</p>
          <p class="result-message">{{ verificationResult.message }}</p>
          <p class="result-date">Vérifié le {{ verificationResult.date }}</p>
        </div>
        <button *ngIf="verificationResult.status !== 'PENDING'" (click)="downloadPdf()" class="btn btn-gold btn-sm">
          📄 Rapport PDF
        </button>
      </div>

      <!-- Pillars -->
      <div class="pillars-section">
        <h2 class="section-title-center">Les 4 Piliers de Confiance</h2>
        <div class="pillars-grid stagger">
          <div class="pillar-card" (click)="navigate('CATALOGUE')">
            <div class="pillar-icon">🏠</div>
            <h3>Acheter</h3>
            <p>Catalogue de terrains certifiés. Filtre « zéro risque » activé.</p>
            <span class="pillar-arrow">→</span>
          </div>
          <div class="pillar-card" (click)="navigate('VERIFY')">
            <div class="pillar-icon">🔍</div>
            <h3>Vérifier</h3>
            <p>Arbitrage notarial express. Rapport en 48 heures.</p>
            <span class="pillar-arrow">→</span>
          </div>
          <div class="pillar-card" (click)="navigate('TITRE')">
            <div class="pillar-icon">📋</div>
            <h3>Titrer</h3>
            <p>Accélérateur administratif MINDCAF. Suivi en temps réel.</p>
            <span class="pillar-arrow">→</span>
          </div>
          <div class="pillar-card" (click)="navigate('PREINVEST')">
            <div class="pillar-icon">💡</div>
            <h3>Pré-Investir</h3>
            <p>maTerre finance le titrage. Vous récoltez la plus-value.</p>
            <span class="pillar-arrow">→</span>
          </div>
        </div>
      </div>
    </section>

    <!-- ─── Sub-views ─── -->
    <section *ngIf="currentView === 'CATALOGUE'" class="view-section animate-in"><app-catalogue></app-catalogue></section>
    <section *ngIf="currentView === 'NOTARY'" class="view-section animate-in"><app-notary-dashboard></app-notary-dashboard></section>
    <section *ngIf="currentView === 'TITRE'" class="view-section animate-in"><app-titling-tracker></app-titling-tracker></section>
    <section *ngIf="currentView === 'PREINVEST'" class="view-section animate-in"><app-pre-invest-dashboard></app-pre-invest-dashboard></section>
    <section *ngIf="currentView === 'COINVEST'" class="view-section animate-in"><app-investment-marketplace></app-investment-marketplace></section>
    <section *ngIf="currentView === 'CLUB'" class="view-section animate-in"><app-subscription></app-subscription></section>
    <section *ngIf="currentView === 'PORTFOLIO'" class="view-section animate-in"><app-investor-dashboard></app-investor-dashboard></section>
    <section *ngIf="currentView === 'ADMIN'" class="view-section animate-in"><app-admin-dashboard></app-admin-dashboard></section>
  </main>

  <!-- ═══ FOOTER ═══ -->
  <footer class="footer">
    <div class="footer-inner">
      <div class="footer-brand">
        <img src="assets/icons/logo.png" alt="maTerre" class="footer-logo">
        <p class="footer-tagline">La Clé d'un Foncier Sûr.</p>
      </div>
      <div class="footer-links">
        <a (click)="navigate('VERIFY')">Vérifier</a>
        <a (click)="navigate('CATALOGUE')">Catalogue</a>
        <a (click)="navigate('TITRE')">Titrer</a>
        <a (click)="navigate('CLUB')">Club Elite</a>
      </div>
      <div class="footer-copy">
        &copy; 2024 maTerre — L'Arbitre du Foncier au Cameroun
      </div>
    </div>
  </footer>

  <!-- ═══ LOGIN MODAL ═══ -->
  <div *ngIf="showLogin" class="modal-overlay" (click)="showLogin = false">
    <div class="modal-content" (click)="$event.stopPropagation()">
      <button (click)="showLogin = false" class="close-btn">✕</button>
      <app-login (loginSuccess)="onLoginSuccess()"></app-login>
    </div>
  </div>
</div>
